import styled from 'styled-components/native';
import { themeDefault, PropsThemeDefault } from '@semparar/design-system-app';

const theme = themeDefault as unknown as PropsThemeDefault;

export const Container = styled.View`
  flex: 1;
  flex-grow: 1;
  padding: 0px 20px;
  justify-content: space-between;
  background: ${theme.colors.INTENSE_COLOR_01};
  position: relative;
  align-items: center;
`;

export const Content = styled.View`
  width: 90%;
  margin: auto;
  align-items: center;
`;

