import * as colors from '../settings/colors';
import * as theme from '../settings/environment';
import { PropsTextFintech } from './fintech/Models/type.text';
import { PropsButtonCore } from './Models/type.button';
import { PropsColorsCore } from './Models/type.colors';
import { PropsTextCore } from './Models/type.text';

export const lightColors: PropsColorsCore = {
  ...colors,
};

const font = {
  principal: 'Ubuntu',
  light: 'Ubuntu-Light',
  regular: 'Ubuntu-Regular',
  medium: 'Ubuntu-Medium',
  bold: 'Ubuntu-Bold',
};

const fontSize = {
  smaller: theme.FONT_SIZE_SMALLER,
  small: theme.FONT_SIZE_SMALL,
  middle: theme.FONT_SIZE_MIDDLE,
