  display1: theme.FONT_SIZE_DISPLAY_1,
  display2: theme.FONT_SIZE_DISPLAY_2,
  display3: theme.FONT_SIZE_DISPLAY_3,
};

const fontWeight = {
  light: theme.FONT_WEIGHT_LIGHT,
  regular: theme.FONT_WEIGHT_REGULAR,
  medium: theme.FONT_WEIGHT_MEDIUM,
  bold: theme.FONT_WEIGHT_BOLD,
};

const borderRadius = {
  none: theme.BORDER_RADIUS_NONE,
