  tight: theme.LINE_HEIGHT_TIGHT,
  fair: theme.LINE_HEIGHT_FAIR,
  distant: theme.LINE_HEIGHT_DISTANT,
};

const letterSpacing = {
  xs: -0.2,
  xxs: -0.4,
};

const spaces = {
  margins: {
    flat: {
      quark: theme.MARGIN_FLAT_QUARK,
